const fs = require('fs');
const path = require('path');
const files = {"src/lib/makes.ts": "/**\n * CarLinx-IA \u2014 Vehicle makes organised by Type\n * Three selectable types: Cars \u00b7 Commercial \u00b7 Motorbikes\n * Each has its own Major + Full makes list.\n */\n\n// \u2500\u2500 CARS \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n\nexport const CAR_MAJOR_MAKES = [\n  'Alfa Romeo', 'Audi', 'BMW', 'Citro\u00ebn', 'Dacia', 'Fiat', 'Ford', 'Honda',\n  'Hyundai', 'Jaguar', 'Jeep', 'Kia', 'Land Rover', 'Lexus', 'Mazda',\n  'Mercedes-Benz', 'MG', 'MINI', 'Mitsubishi', 'Nissan', 'Peugeot', 'Polestar',\n  'Porsche', 'Renault', 'SEAT', '\u0160koda', 'Subaru', 'Suzuki', 'Tesla',\n  'Toyota', 'Vauxhall', 'Volkswagen', 'Volvo',\n];\n\nexport const CAR_ALL_MAKES = [\n  'AC', 'Alfa Romeo', 'Alpine', 'Ariel', 'Aston Martin', 'Audi',\n  'Bentley', 'BMW', 'Bugatti',\n  'Cadillac', 'Caterham', 'Chevrolet', 'Chrysler', 'Citro\u00ebn',\n  'Dacia', 'Daewoo', 'Daihatsu', 'Dodge', 'DS',\n  'Ferrari', 'Fiat', 'Ford', 'Genesis', 'GMC',\n  'Honda', 'Hummer', 'Hyundai',\n  'Infiniti', 'Isuzu',\n  'Jaguar', 'Jeep',\n  'Kia', 'Koenigsegg',\n  'Lamborghini', 'Lancia', 'Land Rover', 'Lexus', 'Lotus',\n  'Maserati', 'Maybach', 'Mazda', 'McLaren', 'Mercedes-Benz',\n  'MG', 'MINI', 'Mitsubishi', 'Morgan',\n  'Nissan',\n  'Pagani', 'Peugeot', 'Polestar', 'Porsche',\n  'RAM', 'Renault', 'Rolls-Royce', 'Rover',\n  'Saab', 'SEAT', '\u0160koda', 'Smart', 'Subaru', 'Suzuki',\n  'Tesla', 'Toyota',\n  'Vauxhall', 'Volkswagen', 'Volvo',\n  'Wiesmann',\n];\n\n// \u2500\u2500 COMMERCIAL \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n\nexport const COMMERCIAL_MAJOR_MAKES = [\n  'DAF', 'Ford', 'Isuzu', 'Iveco', 'LDV', 'MAN', 'Mercedes-Benz',\n  'Mitsubishi', 'Nissan', 'Peugeot', 'Renault', 'Scania', 'Toyota',\n  'Vauxhall', 'Volkswagen', 'Volvo',\n];\n\nexport const COMMERCIAL_ALL_MAKES = [\n  'Ashok Leyland', 'Avia',\n  'BharatBenz',\n  'Caetano', 'Citro\u00ebn',\n  'DAF', 'Dennis',\n  'ERF',\n  'FAW', 'Fiat', 'Ford', 'Foton',\n  'Hino',\n  'Isuzu', 'Iveco',\n  'JAC', 'JCB',\n  'Kenworth',\n  'LDV', 'Leyland', 'Leyland DAF',\n  'MAN', 'Mercedes-Benz', 'Mitsubishi Fuso',\n  'Nissan',\n  'Peugeot', 'Peterbilt',\n  'Renault', 'Renault Trucks',\n  'Scania', 'Seddon Atkinson', 'Sinotruk',\n  'Toyota', 'TruckMAN',\n  'UD Trucks',\n  'Vauxhall', 'Volkswagen', 'Volvo',\n  'Western Star',\n];\n\n// \u2500\u2500 MOTORBIKES \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n\nexport const MOTORBIKE_MAJOR_MAKES = [\n  'Aprilia', 'BMW', 'Ducati', 'Harley-Davidson', 'Honda', 'Husqvarna',\n  'Kawasaki', 'KTM', 'Royal Enfield', 'Suzuki', 'Triumph', 'Yamaha',\n];\n\nexport const MOTORBIKE_ALL_MAKES = [\n  'Aprilia',\n  'Benelli', 'Beta', 'BMW', 'Brough Superior',\n  'CCM', 'CF Moto',\n  'Ducati',\n  'Gas Gas',\n  'Harley-Davidson', 'Honda', 'Husaberg', 'Husqvarna',\n  'Indian',\n  'Kawasaki', 'KTM',\n  'Kymco',\n  'Lambretta',\n  'MV Agusta',\n  'Norton',\n  'Piaggio',\n  'Royal Enfield',\n  'Sherco', 'Suzuki',\n  'Triumph',\n  'Ural',\n  'Vespa',\n  'Yamaha', 'Zero Motorcycles',\n];\n\n// \u2500\u2500 LOOKUP HELPERS \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n\nexport const MAKES_BY_TYPE: Record<string, { major: string[]; all: string[] }> = {\n  car:        { major: CAR_MAJOR_MAKES,        all: CAR_ALL_MAKES },\n  commercial: { major: COMMERCIAL_MAJOR_MAKES, all: COMMERCIAL_ALL_MAKES },\n  motorbike:  { major: MOTORBIKE_MAJOR_MAKES,  all: MOTORBIKE_ALL_MAKES },\n};\n\nexport type VehicleType = 'car' | 'commercial' | 'motorbike';\n\nexport const VEHICLE_TYPES: { value: VehicleType; label: string; icon: string; desc: string }[] = [\n  { value: 'car',        label: 'Cars',       icon: '\ud83d\ude97', desc: 'All passenger cars & sports vehicles' },\n  { value: 'commercial', label: 'Commercial', icon: '\ud83d\ude90', desc: 'Vans, trucks, HGVs & fleet vehicles' },\n  { value: 'motorbike',  label: 'Motorbikes', icon: '\ud83c\udfcd\ufe0f', desc: 'Motorcycles, scooters & mopeds' },\n];\n", "src/lib/api.ts": "/**\n * CarLinx API proxy helper\n * All API calls routed through here \u2014 never direct from components.\n * Backend: vtl-platform-api (unchanged schema)\n */\n\nconst API_BASE = import.meta.env.VTL_API_URL ?? 'https://api.vtl-platform.com';\n\nexport interface Vehicle {\n  id: string;\n  title: string;\n  type: 'car' | 'commercial' | 'motorbike';\n  make: string;\n  model: string;\n  year: number;\n  price: number;\n  mileage: number;\n  fuel: string;\n  transmission: string;\n  body_type?: string;\n  colour?: string;\n  engine_size?: string;\n  doors?: number;\n  // Motorbike-specific\n  engine_cc?: number;\n  bike_type?: string;\n  // Commercial-specific\n  payload_kg?: number;\n  gross_weight_kg?: number;\n  location: string;\n  images: string[];\n  description?: string;\n  seller_name?: string;\n  seller_phone?: string;\n  created_at: string;\n}\n\nexport interface VehicleSearchParams {\n  type?:         string;\n  make?:         string;\n  model?:        string;\n  min_price?:    number;\n  max_price?:    number;\n  max_mileage?:  number;\n  fuel?:         string;\n  transmission?: string;\n  year_from?:    number;\n  body_type?:    string;\n  location?:     string;\n  sort?:         string;\n  page?:         number;\n  limit?:        number;\n}\n\nexport interface VehicleListResponse {\n  vehicles: Vehicle[];\n  total: number;\n  page: number;\n  limit: number;\n}\n\nexport async function getVehicles(\n  params: VehicleSearchParams = {},\n  fetchFn: typeof fetch = fetch\n): Promise<VehicleListResponse> {\n  const query = new URLSearchParams();\n  for (const [k, v] of Object.entries(params)) {\n    if (v !== undefined && v !== '' && v !== null) query.set(k, String(v));\n  }\n  const url = `${API_BASE}/api/vehicles?${query.toString()}`;\n  try {\n    const res = await fetchFn(url, {\n      headers: { 'Accept': 'application/json' },\n      signal: AbortSignal.timeout(8000),\n    });\n    if (!res.ok) throw new Error(`API ${res.status}`);\n    return await res.json() as VehicleListResponse;\n  } catch (err) {\n    console.error('[CarLinx API] getVehicles failed:', err);\n    return { vehicles: [], total: 0, page: 1, limit: 24 };\n  }\n}\n\nexport async function getVehicleById(\n  id: string,\n  fetchFn: typeof fetch = fetch\n): Promise<Vehicle | null> {\n  const url = `${API_BASE}/api/vehicle/${encodeURIComponent(id)}`;\n  try {\n    const res = await fetchFn(url, {\n      headers: { 'Accept': 'application/json' },\n      signal: AbortSignal.timeout(8000),\n    });\n    if (res.status === 404) return null;\n    if (!res.ok) throw new Error(`API ${res.status}`);\n    return await res.json() as Vehicle;\n  } catch (err) {\n    console.error(`[CarLinx API] getVehicleById(${id}) failed:`, err);\n    return null;\n  }\n}\n\nexport function formatPrice(p: number): string {\n  return new Intl.NumberFormat('en-GB', {\n    style: 'currency', currency: 'GBP', maximumFractionDigits: 0,\n  }).format(p);\n}\n\nexport function formatMileage(m: number): string {\n  return new Intl.NumberFormat('en-GB').format(m);\n}\n", "src/components/SearchPanel.astro": "---\nimport { MAKES_BY_TYPE, VEHICLE_TYPES, CAR_MAJOR_MAKES, CAR_ALL_MAKES } from '../lib/makes';\n\nexport interface Props {\n  params?: Record<string, string>;\n}\n\nconst { params = {} } = Astro.props;\n\nconst activeType = (params.type ?? 'car') as 'car' | 'commercial' | 'motorbike';\n\n// Fuel options vary slightly by type\nconst FUELS: Record<string, string[]> = {\n  car:        ['Petrol', 'Diesel', 'Hybrid', 'Plug-in Hybrid', 'Electric', 'LPG', 'Hydrogen', 'Other'],\n  commercial: ['Diesel', 'Petrol', 'Electric', 'LPG', 'Hybrid', 'Other'],\n  motorbike:  ['Petrol', 'Electric', 'Other'],\n};\n\n// Transmission options vary by type\nconst TRANSMISSIONS: Record<string, string[]> = {\n  car:        ['Automatic', 'Manual', 'Semi-Automatic', 'CVT'],\n  commercial: ['Manual', 'Automatic', 'Semi-Automatic'],\n  motorbike:  ['Manual', 'Automatic', 'Semi-Automatic'],\n};\n\n// Body types vary by type\nconst BODY_TYPES: Record<string, string[]> = {\n  car:        ['Saloon', 'Hatchback', 'Estate', 'SUV', 'Coupe', 'Convertible', 'MPV', 'Pickup', 'Other'],\n  commercial: ['Panel Van', 'Crew Van', 'Chassis Cab', 'Tipper', 'Curtainsider', 'Box Van', 'Flatbed', 'Minibus', 'HGV', 'Other'],\n  motorbike:  ['Naked / Streetfighter', 'Sports / Superbike', 'Tourer', 'Adventure / Enduro', 'Cruiser', 'Scooter / Moped', 'Trials', 'Motocross', 'Classic', 'Other'],\n};\n\nconst years = Array.from({ length: 35 }, (_, i) => 2025 - i);\n\n// Pre-serialise all makes data for client-side JS switching\nconst makesData = JSON.stringify({\n  car:        MAKES_BY_TYPE.car,\n  commercial: MAKES_BY_TYPE.commercial,\n  motorbike:  MAKES_BY_TYPE.motorbike,\n});\n\nconst fuelsData       = JSON.stringify(FUELS);\nconst transmissionsData = JSON.stringify(TRANSMISSIONS);\nconst bodyTypesData   = JSON.stringify(BODY_TYPES);\n---\n\n<section class=\"search-section\" aria-label=\"Vehicle search filters\">\n\n  <!-- TYPE SELECTOR TABS -->\n  <div class=\"type-tabs\" role=\"tablist\" aria-label=\"Vehicle type\">\n    {VEHICLE_TYPES.map(t => (\n      <button\n        role=\"tab\"\n        class:list={['type-tab', { active: t.value === activeType }]}\n        data-type={t.value}\n        aria-selected={t.value === activeType ? 'true' : 'false'}\n        onclick={`selectType('${t.value}')`}\n        type=\"button\"\n      >\n        <span class=\"type-icon\" aria-hidden=\"true\">{t.icon}</span>\n        <span class=\"type-label\">{t.label}</span>\n        <span class=\"type-desc\">{t.desc}</span>\n      </button>\n    ))}\n  </div>\n\n  <!-- SEARCH FORM -->\n  <form class=\"search-panel\" method=\"get\" action=\"/\" id=\"search-form\">\n\n    <!-- Hidden type field \u2014 populated by JS -->\n    <input type=\"hidden\" name=\"type\" id=\"f-type\" value={activeType} />\n\n    <!-- Make -->\n    <div class=\"field\">\n      <label for=\"f-make\">Make</label>\n      <select id=\"f-make\" name=\"make\" onchange=\"handleMakeChange(this)\">\n        <option value=\"\">Any Make</option>\n        <optgroup label=\"\u2500\u2500 Popular \u2500\u2500\" id=\"make-major-group\">\n          {MAKES_BY_TYPE[activeType].major.map(m => (\n            <option value={m} selected={params.make === m}>{m}</option>\n          ))}\n        </optgroup>\n        <optgroup label=\"\u2500\u2500 All Makes \u2500\u2500\" id=\"make-all-group\">\n          {MAKES_BY_TYPE[activeType].all\n            .filter(m => !MAKES_BY_TYPE[activeType].major.includes(m))\n            .map(m => (\n              <option value={m} selected={params.make === m}>{m}</option>\n            ))\n          }\n        </optgroup>\n        <option value=\"__other__\">Other / Not Listed</option>\n      </select>\n      <input\n        type=\"text\"\n        id=\"f-make-custom\"\n        name=\"make_custom\"\n        placeholder=\"Enter make\u2026\"\n        class=\"custom-input\"\n        style=\"display:none; margin-top:0.4rem;\"\n        value={params.make_custom ?? ''}\n      />\n    </div>\n\n    <!-- Model -->\n    <div class=\"field\">\n      <label for=\"f-model\">Model</label>\n      <input id=\"f-model\" type=\"text\" name=\"model\" placeholder=\"e.g. Transit, R1, A4\u2026\" value={params.model ?? ''} />\n    </div>\n\n    <!-- Fuel -->\n    <div class=\"field\">\n      <label for=\"f-fuel\">Fuel</label>\n      <select id=\"f-fuel\" name=\"fuel\">\n        <option value=\"\">Any</option>\n        {FUELS[activeType].map(f => (\n          <option value={f.toLowerCase().replace(/ /g,'-')} selected={params.fuel === f.toLowerCase().replace(/ /g,'-')}>{f}</option>\n        ))}\n      </select>\n    </div>\n\n    <!-- Transmission -->\n    <div class=\"field\">\n      <label for=\"f-trans\">Gearbox</label>\n      <select id=\"f-trans\" name=\"transmission\">\n        <option value=\"\">Any</option>\n        {TRANSMISSIONS[activeType].map(t => (\n          <option value={t.toLowerCase().replace(/ /g,'-')} selected={params.transmission === t.toLowerCase().replace(/ /g,'-')}>{t}</option>\n        ))}\n      </select>\n    </div>\n\n    <!-- Body Type -->\n    <div class=\"field\">\n      <label for=\"f-body\">Body Type</label>\n      <select id=\"f-body\" name=\"body_type\">\n        <option value=\"\">Any</option>\n        {BODY_TYPES[activeType].map(b => (\n          <option value={b.toLowerCase().replace(/ \\/ /g,'-').replace(/ /g,'-')} selected={params.body_type === b.toLowerCase().replace(/ \\/ /g,'-').replace(/ /g,'-')}>{b}</option>\n        ))}\n      </select>\n    </div>\n\n    <!-- Min Price -->\n    <div class=\"field\">\n      <label for=\"f-min\">Min Price</label>\n      <select id=\"f-min\" name=\"min_price\">\n        <option value=\"\">No Min</option>\n        {[500,1000,2500,5000,7500,10000,15000,20000,25000,30000,40000,50000,75000,100000].map(p => (\n          <option value={p} selected={params.min_price === String(p)}>\u00a3{p.toLocaleString('en-GB')}</option>\n        ))}\n      </select>\n    </div>\n\n    <!-- Max Price -->\n    <div class=\"field\">\n      <label for=\"f-max\">Max Price</label>\n      <select id=\"f-max\" name=\"max_price\">\n        <option value=\"\">No Max</option>\n        {[3000,5000,7500,10000,15000,20000,25000,30000,40000,50000,75000,100000,150000,200000].map(p => (\n          <option value={p} selected={params.max_price === String(p)}>\u00a3{p.toLocaleString('en-GB')}</option>\n        ))}\n      </select>\n    </div>\n\n    <!-- Max Mileage -->\n    <div class=\"field\">\n      <label for=\"f-mileage\">Max Mileage</label>\n      <select id=\"f-mileage\" name=\"max_mileage\">\n        <option value=\"\">Any</option>\n        {[5000,10000,20000,30000,40000,50000,60000,75000,100000,125000,150000].map(m => (\n          <option value={m} selected={params.max_mileage === String(m)}>{m.toLocaleString('en-GB')} mi</option>\n        ))}\n      </select>\n    </div>\n\n    <!-- Year From -->\n    <div class=\"field\">\n      <label for=\"f-year\">Year From</label>\n      <select id=\"f-year\" name=\"year_from\">\n        <option value=\"\">Any</option>\n        {years.map(y => (\n          <option value={y} selected={params.year_from === String(y)}>{y}</option>\n        ))}\n      </select>\n    </div>\n\n    <!-- Location -->\n    <div class=\"field\">\n      <label for=\"f-location\">Location</label>\n      <input id=\"f-location\" type=\"text\" name=\"location\" placeholder=\"City, postcode, country\u2026\" value={params.location ?? ''} />\n    </div>\n\n    <!-- Search -->\n    <div class=\"field field-submit\">\n      <button type=\"submit\" class=\"btn-search\">\n        <svg width=\"16\" height=\"16\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2.5\" aria-hidden=\"true\">\n          <circle cx=\"11\" cy=\"11\" r=\"8\"/><path d=\"m21 21-4.35-4.35\"/>\n        </svg>\n        Search\n      </button>\n    </div>\n\n  </form>\n</section>\n\n<!-- All dropdown data baked in at build time, switched client-side -->\n<script is:inline define:vars={{ makesData, fuelsData, transmissionsData, bodyTypesData }}>\n  const MAKES        = JSON.parse(makesData);\n  const FUELS_MAP    = JSON.parse(fuelsData);\n  const TRANS_MAP    = JSON.parse(transmissionsData);\n  const BODIES_MAP   = JSON.parse(bodyTypesData);\n\n  function slug(s) { return s.toLowerCase().replace(/ \\/ /g, '-').replace(/ /g, '-'); }\n\n  function rebuildSelect(selectEl, items, currentVal) {\n    const prev = currentVal ?? selectEl.value;\n    while (selectEl.options.length > 1) selectEl.remove(1);\n    items.forEach(item => {\n      const opt = document.createElement('option');\n      opt.value = slug(item);\n      opt.textContent = item;\n      if (slug(item) === prev) opt.selected = true;\n      selectEl.appendChild(opt);\n    });\n  }\n\n  function rebuildMakes(type, currentMake) {\n    const makes = MAKES[type];\n    const majorGroup = document.getElementById('make-major-group');\n    const allGroup   = document.getElementById('make-all-group');\n    if (!majorGroup || !allGroup) return;\n\n    // Clear existing options in groups\n    majorGroup.innerHTML = '';\n    allGroup.innerHTML   = '';\n\n    const majorSet = new Set(makes.major);\n    makes.major.forEach(m => {\n      const opt = document.createElement('option');\n      opt.value = m;\n      opt.textContent = m;\n      if (m === currentMake) opt.selected = true;\n      majorGroup.appendChild(opt);\n    });\n    makes.all.filter(m => !majorSet.has(m)).forEach(m => {\n      const opt = document.createElement('option');\n      opt.value = m;\n      opt.textContent = m;\n      if (m === currentMake) opt.selected = true;\n      allGroup.appendChild(opt);\n    });\n  }\n\n  function selectType(type) {\n    // Update hidden field\n    document.getElementById('f-type').value = type;\n\n    // Update tab active states\n    document.querySelectorAll('.type-tab').forEach(tab => {\n      const isActive = tab.dataset.type === type;\n      tab.classList.toggle('active', isActive);\n      tab.setAttribute('aria-selected', isActive ? 'true' : 'false');\n    });\n\n    // Update hero title/eyebrow\n    const labels = { car: 'Cars', commercial: 'Commercial', motorbike: 'Motorbikes' };\n    const eyebrow = document.querySelector('.hero-eyebrow');\n    if (eyebrow) eyebrow.textContent = `Global ${labels[type]} Discovery`;\n\n    // Rebuild makes\n    rebuildMakes(type, '');\n\n    // Rebuild fuel\n    rebuildSelect(document.getElementById('f-fuel'), FUELS_MAP[type], '');\n\n    // Rebuild transmission\n    rebuildSelect(document.getElementById('f-trans'), TRANS_MAP[type], '');\n\n    // Rebuild body type\n    rebuildSelect(document.getElementById('f-body'), BODIES_MAP[type], '');\n\n    // Update model placeholder\n    const modelPlaceholders = {\n      car:        'e.g. Golf, A4, 3 Series\u2026',\n      commercial: 'e.g. Transit, Sprinter, Daily\u2026',\n      motorbike:  'e.g. R1, CBR, Street Triple\u2026',\n    };\n    const modelInput = document.getElementById('f-model');\n    if (modelInput) modelInput.placeholder = modelPlaceholders[type];\n  }\n\n  function handleMakeChange(sel) {\n    const custom = document.getElementById('f-make-custom');\n    if (!custom) return;\n    if (sel.value === '__other__') {\n      custom.style.display = 'block';\n      custom.required = true;\n      custom.focus();\n    } else {\n      custom.style.display = 'none';\n      custom.required = false;\n      custom.value = '';\n    }\n  }\n\n  // Expose globally\n  window.selectType     = selectType;\n  window.handleMakeChange = handleMakeChange;\n</script>\n\n<style>\n  /* \u2500\u2500 TYPE TABS \u2500\u2500 */\n  .type-tabs {\n    display: flex; gap: 0;\n    border-bottom: 1px solid var(--border);\n    background: var(--black);\n    max-width: 100%;\n    overflow-x: auto;\n    scrollbar-width: none;\n  }\n  .type-tabs::-webkit-scrollbar { display: none; }\n\n  .type-tab {\n    flex: 1; min-width: 120px;\n    display: flex; flex-direction: column; align-items: center; gap: 0.2rem;\n    padding: 1rem 1.5rem 0.875rem;\n    background: transparent; border: none;\n    border-bottom: 3px solid transparent;\n    cursor: pointer; transition: all 0.2s;\n    position: relative;\n  }\n  .type-tab:not(:last-child) { border-right: 1px solid var(--border); }\n\n  .type-tab:hover {\n    background: rgba(255,168,0,0.04);\n  }\n  .type-tab.active {\n    border-bottom-color: var(--amber);\n    background: rgba(255,168,0,0.06);\n  }\n\n  .type-icon { font-size: 1.5rem; line-height: 1; }\n  .type-label {\n    font-family: var(--font-head); font-weight: 700; font-size: 1rem;\n    color: var(--mute); letter-spacing: 0.04em;\n    transition: color 0.2s;\n  }\n  .type-tab.active .type-label, .type-tab:hover .type-label { color: white; }\n  .type-tab.active .type-label { color: var(--amber); }\n\n  .type-desc {\n    font-size: 0.7rem; color: var(--mute);\n    text-align: center; line-height: 1.3;\n    display: none;\n  }\n  @media (min-width: 700px) { .type-desc { display: block; } }\n\n  /* \u2500\u2500 SEARCH PANEL \u2500\u2500 */\n  .search-section {\n    background: var(--panel);\n    border-bottom: 1px solid var(--border);\n  }\n\n  .search-panel {\n    max-width: 1320px; margin: 0 auto;\n    padding: 1.5rem;\n    display: grid;\n    grid-template-columns: repeat(auto-fill, minmax(150px, 1fr));\n    gap: 0.875rem;\n    align-items: end;\n  }\n\n  .field { display: flex; flex-direction: column; }\n  .field label {\n    font-size: 0.7rem; font-weight: 700;\n    letter-spacing: 0.1em; text-transform: uppercase;\n    color: var(--mute); margin-bottom: 0.4rem;\n  }\n  .field select,\n  .field input[type=\"text\"],\n  .custom-input {\n    width: 100%;\n    background: var(--dark);\n    border: 1px solid var(--border);\n    border-radius: 7px;\n    padding: 0.65rem 0.875rem;\n    color: var(--text);\n    font-family: var(--font-body); font-size: 0.9rem;\n    outline: none; appearance: none;\n    transition: border-color 0.2s;\n  }\n  .field select:focus,\n  .field input:focus { border-color: var(--amber); }\n  .field select option,\n  .field select optgroup { background: var(--dark); color: var(--text); }\n\n  .field-submit { justify-content: flex-end; }\n  .btn-search {\n    width: 100%; padding: 0.7rem 1rem;\n    background: var(--amber); color: var(--black);\n    border: none; border-radius: 7px;\n    font-family: var(--font-head); font-weight: 700; font-size: 1rem;\n    letter-spacing: 0.05em; cursor: pointer;\n    display: flex; align-items: center; justify-content: center; gap: 0.5rem;\n    transition: background 0.2s, transform 0.15s;\n  }\n  .btn-search:hover { background: var(--amber-d); transform: translateY(-1px); }\n  .btn-search:active { transform: translateY(0); }\n\n  @media (max-width: 600px) {\n    .search-panel { grid-template-columns: 1fr 1fr; }\n    .field-submit { grid-column: 1 / -1; }\n  }\n</style>\n", "src/components/VehicleCard.astro": "---\nimport type { Vehicle } from '../lib/api';\nimport { formatPrice, formatMileage } from '../lib/api';\n\nexport interface Props {\n  vehicle: Vehicle;\n}\n\nconst { vehicle } = Astro.props;\n\nconst thumb = vehicle.images?.[0] ?? null;\n\nconst typeIcon: Record<string, string> = {\n  car: '\ud83d\ude97', commercial: '\ud83d\ude90', motorbike: '\ud83c\udfcd\ufe0f',\n};\n\nconst fuelIcon: Record<string, string> = {\n  petrol: '\u26fd', diesel: '\ud83d\udee2\ufe0f', hybrid: '\ud83d\udd0b',\n  'plug-in-hybrid': '\ud83d\udd0b', electric: '\u26a1', other: '\u2699\ufe0f',\n};\n\nconst fuelEmoji = fuelIcon[(vehicle.fuel ?? '').toLowerCase().replace(/ /g,'-')] ?? '\u2699\ufe0f';\nconst vehicleIcon = typeIcon[vehicle.type] ?? '\ud83d\ude97';\n\n// Spec rows adapt to vehicle type\nconst specItems = vehicle.type === 'motorbike'\n  ? [\n      { icon: '\ud83d\udccf', val: `${formatMileage(vehicle.mileage)} mi` },\n      { icon: '\u2699\ufe0f', val: vehicle.engine_cc ? `${vehicle.engine_cc}cc` : vehicle.fuel },\n      { icon: '\ud83d\udcc5', val: String(vehicle.year) },\n      { icon: '\ud83d\udccd', val: vehicle.location },\n    ]\n  : vehicle.type === 'commercial'\n  ? [\n      { icon: '\ud83d\udccf', val: `${formatMileage(vehicle.mileage)} mi` },\n      { icon: '\u2699\ufe0f', val: vehicle.fuel },\n      { icon: vehicle.payload_kg ? '\ud83c\udfcb\ufe0f' : '\ud83d\udcc5', val: vehicle.payload_kg ? `${vehicle.payload_kg.toLocaleString('en-GB')}kg payload` : String(vehicle.year) },\n      { icon: '\ud83d\udccd', val: vehicle.location },\n    ]\n  : [\n      { icon: '\ud83d\udccf', val: `${formatMileage(vehicle.mileage)} mi` },\n      { icon: '\ud83d\udd04', val: vehicle.transmission },\n      { icon: '\ud83d\udcc5', val: String(vehicle.year) },\n      { icon: '\ud83d\udccd', val: vehicle.location },\n    ];\n---\n\n<article class=\"card\" data-id={vehicle.id} data-type={vehicle.type}>\n  <a href={`/vehicle/${vehicle.id}`} class=\"card-link\" aria-label={`View ${vehicle.title}`}>\n\n    <div class=\"card-thumb\">\n      {thumb\n        ? <img src={thumb} alt={vehicle.title} loading=\"lazy\" decoding=\"async\" width=\"400\" height=\"220\" />\n        : <span class=\"thumb-placeholder\" aria-hidden=\"true\">{vehicleIcon}</span>\n      }\n      <span class=\"fuel-badge\">{fuelEmoji} {vehicle.fuel}</span>\n      <button\n        class=\"save-btn\"\n        aria-label={`Save ${vehicle.title}`}\n        data-vehicle-id={vehicle.id}\n        onclick=\"event.preventDefault(); window.toggleSave && window.toggleSave(this)\"\n      >\u2661</button>\n    </div>\n\n    <div class=\"card-body\">\n      <div class=\"card-price\">{formatPrice(vehicle.price)}</div>\n      <h2 class=\"card-title\">{vehicle.year} {vehicle.make} {vehicle.model}</h2>\n      <p class=\"card-trim\">{vehicle.title}</p>\n\n      <dl class=\"specs\">\n        {specItems.map(s => (\n          <div class=\"spec\">\n            <dt class=\"sr-only\">{s.icon}</dt>\n            <dd><span aria-hidden=\"true\">{s.icon}</span> {s.val}</dd>\n          </div>\n        ))}\n      </dl>\n\n      <div class=\"card-cta\">View Details \u2192</div>\n    </div>\n  </a>\n</article>\n\n<style>\n  .card {\n    background: var(--card-bg);\n    border: 1px solid var(--border);\n    border-radius: 12px;\n    overflow: hidden;\n    transition: transform 0.25s, border-color 0.25s, box-shadow 0.25s;\n  }\n  .card:hover {\n    transform: translateY(-4px);\n    border-color: rgba(255,168,0,0.35);\n    box-shadow: 0 16px 40px rgba(0,0,0,0.45);\n  }\n  .card-link { display: block; text-decoration: none; color: inherit; }\n\n  .card-thumb {\n    position: relative; height: 200px;\n    background: linear-gradient(135deg, #1e2028, #252830);\n    display: flex; align-items: center; justify-content: center;\n    overflow: hidden;\n  }\n  .card-thumb img { width: 100%; height: 100%; object-fit: cover; transition: transform 0.4s; }\n  .card:hover .card-thumb img { transform: scale(1.04); }\n  .card-thumb::after {\n    content: ''; position: absolute; bottom: 0; left: 0; right: 0; height: 50%;\n    background: linear-gradient(transparent, rgba(12,12,12,0.55));\n  }\n  .thumb-placeholder { font-size: 4rem; }\n\n  .fuel-badge {\n    position: absolute; top: 0.875rem; left: 0.875rem; z-index: 1;\n    background: rgba(0,0,0,0.72); backdrop-filter: blur(8px);\n    border: 1px solid var(--border);\n    padding: 0.28rem 0.6rem; border-radius: 5px;\n    font-size: 0.72rem; font-weight: 600; color: var(--text);\n    letter-spacing: 0.06em; text-transform: uppercase;\n  }\n  .save-btn {\n    position: absolute; top: 0.875rem; right: 0.875rem; z-index: 2;\n    width: 34px; height: 34px;\n    background: rgba(0,0,0,0.65); backdrop-filter: blur(8px);\n    border: 1px solid var(--border); border-radius: 7px;\n    display: flex; align-items: center; justify-content: center;\n    font-size: 1rem; cursor: pointer; transition: all 0.2s; color: var(--text);\n  }\n  .save-btn:hover, .save-btn.saved { background: rgba(255,168,0,0.2); border-color: var(--amber); color: var(--amber); }\n\n  .card-body { padding: 1.25rem; }\n  .card-price {\n    font-family: var(--font-head); font-weight: 800; font-size: 1.75rem;\n    color: var(--amber); line-height: 1; margin-bottom: 0.35rem;\n  }\n  .card-title {\n    font-family: var(--font-head); font-weight: 700; font-size: 1.15rem;\n    color: white; margin-bottom: 0.15rem;\n  }\n  .card-trim { font-size: 0.82rem; color: var(--mute); margin-bottom: 1rem; white-space: nowrap; overflow: hidden; text-overflow: ellipsis; }\n\n  .specs {\n    display: grid; grid-template-columns: 1fr 1fr; gap: 0.45rem;\n    background: rgba(255,255,255,0.03); border-radius: 8px;\n    padding: 0.875rem; margin-bottom: 1rem; list-style: none;\n  }\n  .spec dd { font-size: 0.82rem; color: var(--mute); display: flex; align-items: center; gap: 0.35rem; }\n\n  .card-cta {\n    width: 100%; padding: 0.75rem;\n    background: var(--amber); color: var(--black);\n    border-radius: 7px;\n    font-family: var(--font-head); font-weight: 700; font-size: 1rem;\n    text-align: center; letter-spacing: 0.04em; transition: background 0.2s;\n  }\n  .card:hover .card-cta { background: var(--amber-d); }\n</style>\n", "src/pages/index.astro": "---\nimport BaseLayout from '../layouts/BaseLayout.astro';\nimport SearchPanel from '../components/SearchPanel.astro';\nimport VehicleCard from '../components/VehicleCard.astro';\nimport { getVehicles } from '../lib/api';\nimport { VEHICLE_TYPES } from '../lib/makes';\n\nconst url    = new URL(Astro.request.url);\nconst params: Record<string, string> = {};\nurl.searchParams.forEach((v, k) => { if (v) params[k] = v; });\n\nconst activeType = params.type ?? 'car';\nconst activeTypeInfo = VEHICLE_TYPES.find(t => t.value === activeType) ?? VEHICLE_TYPES[0];\n\nconst searchParams = {\n  type:         activeType,\n  make:         params.make_custom || params.make || undefined,\n  model:        params.model        || undefined,\n  fuel:         params.fuel         || undefined,\n  transmission: params.transmission || undefined,\n  body_type:    params.body_type    || undefined,\n  min_price:    params.min_price    ? Number(params.min_price)   : undefined,\n  max_price:    params.max_price    ? Number(params.max_price)   : undefined,\n  max_mileage:  params.max_mileage  ? Number(params.max_mileage) : undefined,\n  year_from:    params.year_from    ? Number(params.year_from)   : undefined,\n  location:     params.location     || undefined,\n  sort:         params.sort         || 'created_at_desc',\n  page:         params.page         ? Number(params.page) : 1,\n  limit:        24,\n};\n\nconst { vehicles, total } = await getVehicles(searchParams, fetch);\n\nconst hasSearch = !!(params.make || params.model || params.fuel || params.min_price ||\n  params.max_price || params.max_mileage || params.year_from || params.location || params.body_type);\n\nconst totalPages  = Math.ceil(total / 24);\nconst currentPage = searchParams.page ?? 1;\n\nfunction buildPageUrl(page: number) {\n  const p = new URLSearchParams(url.searchParams);\n  p.set('page', String(page));\n  return `/?${p.toString()}`;\n}\n---\n\n<BaseLayout\n  title={`CarLinx \u2014 ${activeTypeInfo.label} Discovery`}\n  description={`Search ${activeTypeInfo.label.toLowerCase()} for sale worldwide. Filter by make, model, price, mileage and more.`}\n>\n\n  <!-- HERO -->\n  <section class=\"hero\">\n    <div class=\"hero-inner\">\n      <p class=\"hero-eyebrow\">Global {activeTypeInfo.label} Discovery</p>\n      <h1 class=\"hero-title\">Find Your Next<br /><em>Great {activeTypeInfo.label === 'Cars' ? 'Drive' : activeTypeInfo.label === 'Motorbikes' ? 'Ride' : 'Vehicle'}</em></h1>\n      <p class=\"hero-sub\">Search vehicles for sale worldwide \u2014 every make, every price point.</p>\n    </div>\n  </section>\n\n  <!-- SEARCH PANEL (type tabs + filters) -->\n  <SearchPanel params={params} />\n\n  <!-- RESULTS BAR -->\n  <div class=\"results-bar\">\n    <div class=\"results-inner\">\n      <p class=\"results-count\" aria-live=\"polite\">\n        {total > 0\n          ? <><strong>{total.toLocaleString('en-GB')}</strong> {activeTypeInfo.label.toLowerCase()} found</>\n          : hasSearch\n            ? `No ${activeTypeInfo.label.toLowerCase()} matched your search`\n            : `Select filters to search ${activeTypeInfo.label.toLowerCase()}`\n        }\n      </p>\n      <div class=\"sort-group\">\n        <label for=\"sort-sel\">Sort</label>\n        <form method=\"get\" id=\"sort-form\">\n          {Object.entries(params).filter(([k]) => k !== 'sort' && k !== 'page').map(([k, v]) => (\n            <input type=\"hidden\" name={k} value={v} />\n          ))}\n          <select id=\"sort-sel\" name=\"sort\" onchange=\"this.form.submit()\">\n            <option value=\"created_at_desc\" selected={!params.sort || params.sort === 'created_at_desc'}>Newest Listed</option>\n            <option value=\"price_asc\"       selected={params.sort === 'price_asc'}>Price: Low\u2013High</option>\n            <option value=\"price_desc\"      selected={params.sort === 'price_desc'}>Price: High\u2013Low</option>\n            <option value=\"mileage_asc\"     selected={params.sort === 'mileage_asc'}>Mileage: Low\u2013High</option>\n            <option value=\"year_desc\"       selected={params.sort === 'year_desc'}>Year: Newest</option>\n          </select>\n        </form>\n      </div>\n    </div>\n  </div>\n\n  <!-- GRID / EMPTY STATES -->\n  {vehicles.length > 0 ? (\n    <section class=\"grid-section\" aria-label={`${activeTypeInfo.label} results`}>\n      <div class=\"vehicle-grid\">\n        {vehicles.map((v, i) => (\n          <div class=\"fade-up\" style={`animation-delay:${Math.min(i * 0.05, 0.4)}s`}>\n            <VehicleCard vehicle={v} />\n          </div>\n        ))}\n      </div>\n      {totalPages > 1 && (\n        <nav class=\"pagination\" aria-label=\"Page navigation\">\n          {currentPage > 1   && <a href={buildPageUrl(currentPage - 1)} class=\"page-btn\">\u2190 Prev</a>}\n          <span class=\"page-info\">Page {currentPage} of {totalPages}</span>\n          {currentPage < totalPages && <a href={buildPageUrl(currentPage + 1)} class=\"page-btn\">Next \u2192</a>}\n        </nav>\n      )}\n    </section>\n  ) : hasSearch ? (\n    <div class=\"empty-state\">\n      <div class=\"empty-icon\">{activeTypeInfo.icon}</div>\n      <h2>No {activeTypeInfo.label.toLowerCase()} found</h2>\n      <p>Try adjusting your filters \u2014 remove a few criteria to broaden your results.</p>\n      <a href={`/?type=${activeType}`} class=\"btn-clear\">Clear filters</a>\n    </div>\n  ) : (\n    <div class=\"empty-state\">\n      <div class=\"empty-icon\">{activeTypeInfo.icon}</div>\n      <h2>Search {activeTypeInfo.label}</h2>\n      <p>Use the filters above to start your search \u2014 every field is optional.</p>\n    </div>\n  )}\n\n</BaseLayout>\n\n<script>\n  function toggleSave(btn: HTMLButtonElement) {\n    const id = btn.dataset.vehicleId;\n    if (!id) return;\n    const saved: string[] = JSON.parse(localStorage.getItem('cl_saved') ?? '[]');\n    const idx = saved.indexOf(id);\n    if (idx > -1) { saved.splice(idx, 1); btn.classList.remove('saved'); }\n    else          { saved.push(id);        btn.classList.add('saved'); }\n    localStorage.setItem('cl_saved', JSON.stringify(saved));\n  }\n  document.addEventListener('DOMContentLoaded', () => {\n    const saved: string[] = JSON.parse(localStorage.getItem('cl_saved') ?? '[]');\n    saved.forEach(id => {\n      document.querySelector<HTMLButtonElement>(`.save-btn[data-vehicle-id=\"${id}\"]`)?.classList.add('saved');\n    });\n  });\n  (window as any).toggleSave = toggleSave;\n</script>\n\n<style>\n  .hero {\n    background: linear-gradient(150deg, #0C0C0C 0%, #160D00 60%, #0C0C0C 100%);\n    border-bottom: 1px solid var(--border);\n    padding: 3rem 1.5rem 2.5rem; position: relative; overflow: hidden;\n  }\n  .hero::before {\n    content: ''; position: absolute; inset: 0;\n    background: radial-gradient(ellipse 70% 90% at 75% 50%, rgba(255,168,0,0.07), transparent 70%);\n    pointer-events: none;\n  }\n  .hero-inner { max-width: 1320px; margin: 0 auto; position: relative; }\n  .hero-eyebrow {\n    font-family: var(--font-head); font-weight: 700;\n    font-size: 0.75rem; letter-spacing: 0.2em; text-transform: uppercase;\n    color: var(--amber); margin-bottom: 0.625rem;\n  }\n  .hero-title {\n    font-family: var(--font-head); font-weight: 900;\n    font-size: clamp(2.2rem, 5.5vw, 3.8rem);\n    color: white; line-height: 1; margin-bottom: 0.5rem;\n  }\n  .hero-title em { color: var(--amber); font-style: normal; }\n  .hero-sub { color: var(--mute); font-size: 1rem; }\n\n  .results-bar { border-bottom: 1px solid var(--border); padding: 0.875rem 1.5rem; }\n  .results-inner {\n    max-width: 1320px; margin: 0 auto;\n    display: flex; justify-content: space-between; align-items: center;\n    flex-wrap: wrap; gap: 0.75rem;\n  }\n  .results-count { font-size: 0.95rem; color: var(--mute); }\n  .results-count strong { color: var(--amber); font-size: 1.1rem; }\n\n  .sort-group { display: flex; align-items: center; gap: 0.5rem; }\n  .sort-group label { font-size: 0.8rem; color: var(--mute); font-weight: 600; }\n  .sort-group select {\n    background: var(--panel); border: 1px solid var(--border);\n    border-radius: 7px; padding: 0.4rem 0.75rem;\n    color: var(--text); font-family: var(--font-body); font-size: 0.875rem; outline: none;\n  }\n\n  .grid-section { max-width: 1320px; margin: 0 auto; padding: 2rem 1.5rem 4rem; }\n  .vehicle-grid {\n    display: grid;\n    grid-template-columns: repeat(auto-fill, minmax(300px, 1fr));\n    gap: 1.25rem; margin-bottom: 3rem;\n  }\n\n  .pagination {\n    display: flex; align-items: center; justify-content: center; gap: 1.25rem;\n    padding-top: 1rem; border-top: 1px solid var(--border);\n  }\n  .page-btn {\n    padding: 0.6rem 1.25rem; border-radius: 7px;\n    border: 1px solid var(--border); background: var(--panel);\n    color: var(--text); text-decoration: none; font-weight: 600; transition: all 0.2s;\n  }\n  .page-btn:hover { border-color: var(--amber); color: var(--amber); }\n  .page-info { color: var(--mute); font-size: 0.9rem; }\n\n  .empty-state {\n    max-width: 440px; margin: 5rem auto; padding: 0 1.5rem; text-align: center;\n  }\n  .empty-icon { font-size: 3.5rem; margin-bottom: 1.25rem; }\n  .empty-state h2 {\n    font-family: var(--font-head); font-weight: 800; font-size: 1.8rem;\n    color: white; margin-bottom: 0.75rem;\n  }\n  .empty-state p { color: var(--mute); margin-bottom: 1.5rem; }\n  .btn-clear {\n    display: inline-block; padding: 0.7rem 1.5rem;\n    background: var(--amber); color: var(--black); border-radius: 7px;\n    font-family: var(--font-head); font-weight: 700; font-size: 1rem;\n    text-decoration: none; transition: background 0.2s;\n  }\n  .btn-clear:hover { background: var(--amber-d); }\n\n  @media (max-width: 640px) { .vehicle-grid { grid-template-columns: 1fr; } }\n</style>\n", "src/pages/vehicle/[id].astro": "---\nimport BaseLayout from '../../layouts/BaseLayout.astro';\nimport { getVehicleById, formatPrice, formatMileage } from '../../lib/api';\n\nconst { id } = Astro.params;\nif (!id) return Astro.redirect('/');\n\nconst vehicle = await getVehicleById(id, fetch);\nif (!vehicle) return new Response(null, { status: 404 });\n\nconst typeLabel = { car: 'Cars', commercial: 'Commercial', motorbike: 'Motorbikes' }[vehicle.type] ?? 'Vehicles';\nconst typeIcon  = { car: '\ud83d\ude97', commercial: '\ud83d\ude90', motorbike: '\ud83c\udfcd\ufe0f' }[vehicle.type] ?? '\ud83d\ude97';\n\n// Build spec list appropriate to vehicle type\nconst baseSpecs = [\n  { label: 'Make',         value: vehicle.make },\n  { label: 'Model',        value: vehicle.model },\n  { label: 'Year',         value: String(vehicle.year) },\n  { label: 'Fuel',         value: vehicle.fuel },\n  { label: 'Transmission', value: vehicle.transmission },\n  { label: 'Mileage',      value: `${formatMileage(vehicle.mileage)} miles` },\n  { label: 'Colour',       value: vehicle.colour },\n  { label: 'Location',     value: vehicle.location },\n];\n\nconst typeSpecs = vehicle.type === 'motorbike'\n  ? [\n      { label: 'Engine',    value: vehicle.engine_cc ? `${vehicle.engine_cc}cc` : vehicle.engine_size },\n      { label: 'Bike Type', value: vehicle.bike_type },\n    ]\n  : vehicle.type === 'commercial'\n  ? [\n      { label: 'Body Type',       value: vehicle.body_type },\n      { label: 'Engine',          value: vehicle.engine_size },\n      { label: 'Payload',         value: vehicle.payload_kg ? `${vehicle.payload_kg.toLocaleString('en-GB')} kg` : undefined },\n      { label: 'Gross Weight',    value: vehicle.gross_weight_kg ? `${vehicle.gross_weight_kg.toLocaleString('en-GB')} kg` : undefined },\n    ]\n  : [\n      { label: 'Body Type', value: vehicle.body_type },\n      { label: 'Engine',    value: vehicle.engine_size },\n      { label: 'Doors',     value: vehicle.doors ? String(vehicle.doors) : undefined },\n    ];\n\nconst allSpecs = [...baseSpecs, ...typeSpecs].filter(s => s.value);\n\nconst mainImage    = vehicle.images?.[0] ?? null;\nconst galleryImages = vehicle.images?.slice(1) ?? [];\n---\n\n<BaseLayout\n  title={`${vehicle.title} \u2014 CarLinx`}\n  description={`${vehicle.year} ${vehicle.make} ${vehicle.model} \u2014 ${formatPrice(vehicle.price)} \u2014 ${formatMileage(vehicle.mileage)} miles.`}\n  ogImage={mainImage ?? undefined}\n>\n  <!-- BREADCRUMB -->\n  <nav class=\"breadcrumb\" aria-label=\"Breadcrumb\">\n    <div class=\"breadcrumb-inner\">\n      <a href={`/?type=${vehicle.type}`}>{typeIcon} {typeLabel}</a>\n      <span aria-hidden=\"true\">\u203a</span>\n      <a href={`/?type=${vehicle.type}&make=${encodeURIComponent(vehicle.make)}`}>{vehicle.make}</a>\n      <span aria-hidden=\"true\">\u203a</span>\n      <span aria-current=\"page\">{vehicle.model}</span>\n    </div>\n  </nav>\n\n  <div class=\"detail-layout\">\n\n    <!-- GALLERY -->\n    <section class=\"gallery-section\" aria-label=\"Vehicle images\">\n      <div class=\"main-image\">\n        {mainImage\n          ? <img id=\"main-img\" src={mainImage} alt={vehicle.title} width=\"800\" height=\"500\" loading=\"eager\" decoding=\"async\" />\n          : <div class=\"image-placeholder\" aria-label=\"No image\">{typeIcon}</div>\n        }\n      </div>\n      {galleryImages.length > 0 && (\n        <div class=\"thumb-strip\">\n          {galleryImages.map((img, i) => (\n            <button class=\"thumb\" aria-label={`Photo ${i + 2}`} onclick={`setMainImage('${img}')`} type=\"button\">\n              <img src={img} alt={`Photo ${i + 2}`} width=\"120\" height=\"80\" loading=\"lazy\" decoding=\"async\" />\n            </button>\n          ))}\n        </div>\n      )}\n    </section>\n\n    <!-- INFO PANEL -->\n    <aside class=\"info-panel\">\n\n      <div class=\"price-block\">\n        <div class=\"detail-price\">{formatPrice(vehicle.price)}</div>\n        <h1 class=\"detail-title\">{vehicle.year} {vehicle.make} {vehicle.model}</h1>\n        <p class=\"detail-trim\">{vehicle.title}</p>\n      </div>\n\n      <div class=\"key-stats\">\n        <div class=\"stat\">\n          <span class=\"stat-icon\">\ud83d\udccf</span>\n          <span class=\"stat-val\">{formatMileage(vehicle.mileage)}</span>\n          <span class=\"stat-lbl\">miles</span>\n        </div>\n        <div class=\"stat\">\n          <span class=\"stat-icon\">\u2699\ufe0f</span>\n          <span class=\"stat-val\">{vehicle.fuel}</span>\n          <span class=\"stat-lbl\">fuel</span>\n        </div>\n        <div class=\"stat\">\n          <span class=\"stat-icon\">{vehicle.type === 'motorbike' ? '\ud83c\udfcd\ufe0f' : '\ud83d\udd04'}</span>\n          <span class=\"stat-val\">{vehicle.type === 'motorbike' && vehicle.engine_cc ? `${vehicle.engine_cc}cc` : vehicle.transmission}</span>\n          <span class=\"stat-lbl\">{vehicle.type === 'motorbike' ? 'engine' : 'gearbox'}</span>\n        </div>\n        <div class=\"stat\">\n          <span class=\"stat-icon\">\ud83d\udccd</span>\n          <span class=\"stat-val\">{vehicle.location}</span>\n          <span class=\"stat-lbl\">location</span>\n        </div>\n      </div>\n\n      <div class=\"contact-actions\">\n        {vehicle.seller_phone && (\n          <a href={`tel:${vehicle.seller_phone}`} class=\"btn-contact btn-call\">\ud83d\udcde Call Seller</a>\n        )}\n        <a href={`mailto:?subject=Enquiry: ${encodeURIComponent(vehicle.title)}`} class=\"btn-contact btn-enquire\">\u2709\ufe0f Send Enquiry</a>\n      </div>\n\n      <div class=\"spec-table-wrap\">\n        <h2 class=\"section-heading\">Full Specification</h2>\n        <dl class=\"spec-table\">\n          {allSpecs.map(s => (\n            <><dt>{s.label}</dt><dd>{s.value}</dd></>\n          ))}\n        </dl>\n      </div>\n\n      {vehicle.description && (\n        <div>\n          <h2 class=\"section-heading\">Description</h2>\n          <p class=\"description\">{vehicle.description}</p>\n        </div>\n      )}\n\n      {vehicle.seller_name && (\n        <div class=\"seller-block\">\n          <span class=\"seller-label\">Listed by</span>\n          <span class=\"seller-name\">{vehicle.seller_name}</span>\n        </div>\n      )}\n\n    </aside>\n  </div>\n\n  <div class=\"back-row\">\n    <a href={`/?type=${vehicle.type}`} class=\"btn-back\">\u2190 Back to {typeLabel}</a>\n  </div>\n</BaseLayout>\n\n<script is:inline>\n  function setMainImage(src) {\n    const img = document.getElementById('main-img');\n    if (img) img.src = src;\n  }\n</script>\n\n<style>\n  .breadcrumb {\n    border-bottom: 1px solid var(--border); padding: 0.75rem 1.5rem;\n  }\n  .breadcrumb-inner {\n    max-width: 1320px; margin: 0 auto;\n    display: flex; align-items: center; gap: 0.5rem;\n    font-size: 0.83rem; color: var(--mute);\n  }\n  .breadcrumb a { color: var(--mute); text-decoration: none; }\n  .breadcrumb a:hover { color: var(--amber); }\n\n  .detail-layout {\n    max-width: 1320px; margin: 0 auto; padding: 2rem 1.5rem;\n    display: grid; grid-template-columns: 1fr 400px; gap: 2rem; align-items: start;\n  }\n\n  .main-image {\n    background: var(--panel); border-radius: 12px; overflow: hidden;\n    aspect-ratio: 16/10; display: flex; align-items: center; justify-content: center;\n  }\n  .main-image img { width: 100%; height: 100%; object-fit: cover; }\n  .image-placeholder { font-size: 5rem; }\n\n  .thumb-strip { display: flex; gap: 0.625rem; flex-wrap: wrap; margin-top: 0.75rem; }\n  .thumb {\n    width: 90px; height: 62px; border-radius: 7px; overflow: hidden;\n    border: 2px solid var(--border); cursor: pointer; background: none; padding: 0;\n    transition: border-color 0.2s;\n  }\n  .thumb:hover { border-color: var(--amber); }\n  .thumb img { width: 100%; height: 100%; object-fit: cover; }\n\n  .info-panel {\n    background: var(--card-bg); border: 1px solid var(--border);\n    border-radius: 12px; padding: 1.75rem;\n    display: flex; flex-direction: column; gap: 1.5rem;\n    position: sticky; top: 80px;\n  }\n\n  .detail-price {\n    font-family: var(--font-head); font-weight: 900; font-size: 2.4rem;\n    color: var(--amber); line-height: 1;\n  }\n  .detail-title {\n    font-family: var(--font-head); font-weight: 800; font-size: 1.5rem;\n    color: white; margin: 0.3rem 0 0.15rem;\n  }\n  .detail-trim { font-size: 0.9rem; color: var(--mute); }\n\n  .key-stats { display: grid; grid-template-columns: 1fr 1fr; gap: 0.875rem; }\n  .stat {\n    background: var(--panel); border-radius: 8px; padding: 0.875rem;\n    display: flex; flex-direction: column; gap: 0.2rem;\n  }\n  .stat-icon { font-size: 1.1rem; }\n  .stat-val { font-family: var(--font-head); font-weight: 700; font-size: 1rem; color: white; }\n  .stat-lbl { font-size: 0.72rem; color: var(--mute); text-transform: uppercase; letter-spacing: 0.07em; }\n\n  .contact-actions { display: flex; flex-direction: column; gap: 0.625rem; }\n  .btn-contact {\n    display: block; width: 100%; padding: 0.875rem;\n    border-radius: 8px; text-align: center;\n    font-family: var(--font-head); font-weight: 700; font-size: 1.05rem;\n    text-decoration: none; transition: all 0.2s; letter-spacing: 0.04em;\n  }\n  .btn-call    { background: var(--amber); color: var(--black); }\n  .btn-call:hover { background: var(--amber-d); }\n  .btn-enquire { background: var(--panel); color: var(--text); border: 1px solid var(--border); }\n  .btn-enquire:hover { border-color: var(--amber); color: var(--amber); }\n\n  .section-heading {\n    font-family: var(--font-head); font-weight: 700; font-size: 1rem;\n    text-transform: uppercase; letter-spacing: 0.08em; color: var(--mute); margin-bottom: 0.875rem;\n  }\n  .spec-table { display: grid; grid-template-columns: auto 1fr; gap: 0.5rem 1.25rem; }\n  .spec-table dt { font-size: 0.83rem; color: var(--mute); }\n  .spec-table dd { font-size: 0.9rem; color: var(--text); font-weight: 500; }\n\n  .description { font-size: 0.9rem; color: var(--mute); line-height: 1.7; }\n\n  .seller-block {\n    display: flex; align-items: center; gap: 0.625rem;\n    padding-top: 0.875rem; border-top: 1px solid var(--border); font-size: 0.85rem;\n  }\n  .seller-label { color: var(--mute); }\n  .seller-name  { color: var(--text); font-weight: 600; }\n\n  .back-row { max-width: 1320px; margin: 0 auto; padding: 0 1.5rem 3rem; }\n  .btn-back {\n    display: inline-block; padding: 0.6rem 1.25rem;\n    border: 1px solid var(--border); border-radius: 7px;\n    color: var(--mute); text-decoration: none; font-size: 0.875rem; transition: all 0.2s;\n  }\n  .btn-back:hover { border-color: var(--amber); color: var(--amber); }\n\n  @media (max-width: 900px) {\n    .detail-layout { grid-template-columns: 1fr; }\n    .info-panel { position: static; }\n  }\n</style>\n"};

for (const [filePath, content] of Object.entries(files)) {
  const dir = path.dirname(filePath);
  if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true });
  fs.writeFileSync(filePath, content, 'utf8');
  console.log('✓ Written:', filePath, '(' + content.length + ' chars)');
}
console.log('\nAll 6 files updated successfully!');
